package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsNullStringSetWhenNullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withNullString(null);
        // Use reflection to set nullString field to null explicitly
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // nullString is a private final field, so remove final modifier via reflection
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(nullStringField, nullStringField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        nullStringField.set(format, null);
        assertFalse(format.isNullStringSet());
    }

    @Test
    void testIsNullStringSetWhenNullStringIsNonNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        // Use reflection to set nullString field to "NULL" explicitly
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // nullString is a private final field, so remove final modifier via reflection
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(nullStringField, nullStringField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        nullStringField.set(format, "NULL");
        assertTrue(format.isNullStringSet());
    }
}
